#!/usr/bin/env python3
"""Block `pnpm test` (interactive watcher); steer Claude to `pnpm test:ci`."""
import json, sys

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    if ev.get("tool_name") != "Bash":
        return 0
    cmd = (ev.get("tool_input") or {}).get("command", "")
    if cmd.strip().startswith("pnpm test") and "test:ci" not in cmd:
        print("Use `pnpm test:ci` instead — `pnpm test` opens an interactive watcher and hangs.", file=sys.stderr)
        return 2
    return 0

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
import json, sys, re

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool  = ev.get("tool_name", "")
    inp   = ev.get("tool_input") or {}

    # Only check Python source edits
    if tool not in ("Edit", "Write"):
        return 0

    file_path = inp.get("file_path", "")
    if not file_path.endswith(".py"):
        return 0

    # Get the new content
    if tool == "Edit":
        content = inp.get("new_string", "")
    else:  # Write
        content = inp.get("content", "")

    # Find all function definitions
    func_pattern = r"^def\s+(\w+)\s*\("

    for func_match in re.finditer(func_pattern, content, re.MULTILINE):
        func_name = func_match.group(1)
        func_start = func_match.end()

        # Extract function body (until next "def " or end of file)
        rest = content[func_start:]
        next_def_match = re.search(r"\ndef\s+", rest)
        if next_def_match:
            func_body = rest[:next_def_match.start()]
        else:
            func_body = rest

        # Check if function has tree/traverse keywords in name
        is_tree_func = any(keyword in func_name.lower() for keyword in [
            "tree", "walk", "traverse", "visit"
        ])

        if not is_tree_func:
            continue

        # Check if it calls itself (is recursive)
        if not re.search(rf"\b{re.escape(func_name)}\s*\(", func_body):
            continue

        # It's recursive. Check for depth-limiting patterns
        has_limit = any(keyword in func_body for keyword in [
            "worklist", "stack", "queue", "iterative", "limit",
            "max_depth", "depth_limit", "yield from", "yield"
        ])

        if not has_limit:
            print(
                f"REQUIRED FOLLOW-UP: Recursive function '{func_name}' in {file_path} "
                f"lacks depth limits. Unbounded recursion will crash on large trees (>1000 nodes). "
                f"Use iterative (worklist/queue), explicit max_depth parameter, or generators.",
                file=sys.stderr
            )
            return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())

import json
import sys
import subprocess

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool_name = ev.get("tool_name", "")
    tool_input = ev.get("tool_input") or {}

    if tool_name != "Edit":
        return 0

    file_path = tool_input.get("file_path", "")
    if not file_path or not file_path.endswith(".py"):
        return 0

    try:
        # Auto-format the file
        subprocess.run(["ruff", "format", file_path], capture_output=True, timeout=5)

        # Check for linting issues
        result = subprocess.run(
            ["ruff", "check", file_path],
            capture_output=True,
            text=True,
            timeout=5
        )

        if result.returncode != 0 and result.stdout.strip():
            print(f"⚠️ REQUIRED FOLLOW-UP: Python linting issues detected in {file_path}:\n{result.stdout}",
                  file=sys.stderr)
            return 2
    except (subprocess.TimeoutExpired, FileNotFoundError, Exception):
        return 0

    return 0

if __name__ == "__main__":
    sys.exit(main())

import json, sys, re

def is_secret_pattern(text):
    if not isinstance(text, str):
        return False
    patterns = [
        r'["\']sk-[A-Za-z0-9]{20,}',
        r'["\']sk_[A-Za-z0-9]{20,}',
        r'api[_-]?key["\']?\s*[:=]\s*["\'][A-Za-z0-9\-_]{15,}',
        r'(password|passwd|secret|token)\s*[:=]\s*["\'][^"\']{ 15,}',
        r'-----BEGIN (RSA|OPENSSH|PGP|DSA|EC|PRIVATE)',
    ]
    for pattern in patterns:
        if re.search(pattern, text, re.IGNORECASE):
            return True
    return False

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}
    if tool != "Edit":
        return 0
    file_path = inp.get("file_path", "")
    new_string = inp.get("new_string", "")
    if any(x in file_path for x in ['.env', 'README', 'example', 'test', 'spec']):
        return 0
    if is_secret_pattern(new_string):
        msg = "BLOCKED: Hardcoded secret detected.\nREQUIRED FOLLOW-UP: Read secrets from environment variables (process.env).\nFile: {}\nSee CLAUDE.md: 'Secrets come from the environment.'".format(file_path)
        print(msg, file=sys.stderr)
        return 2
    return 0

if __name__ == "__main__":
    sys.exit(main())

import json, sys, re

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    if tool != "Bash":
        return 0

    command = inp.get("command", "")
    if "git commit" not in command:
        return 0

    # Extract message from -m "..." or -m '...'
    match = re.search(r'-m\s+["\']([^"\']*)["\'\']', command)
    if not match:
        return 0

    message = match.group(1)

    # Team convention: single-line imperative (e.g., "Refactor auth: extract token validation")
    # Reject multi-paragraph or multi-line messages
    if "\n" in message:
        print("Do not continue. Commit message must be a single line (e.g., 'Refactor auth: extract token validation'). This project uses short imperative subject lines, not paragraphs. REQUIRED FOLLOW-UP: rewrite as a single-line imperative.", file=sys.stderr)
        return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())

