"""Block `git add/commit` of .env files; prevents committing secrets."""
import json, sys

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    if tool != "Bash":
        return 0

    cmd = inp.get("command", "")

    # Detect git add/commit with .env files
    if ("git add" in cmd or "git commit" in cmd) and ".env" in cmd:
        print("BLOCKING: Do not commit .env files (may contain secrets). Add .env to .gitignore. CLAUDE.md: 'never commit a real .env'.", file=sys.stderr)
        return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""After editing a Python file in src/, remind to run tests."""
import json, sys

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    if ev.get("tool_name") != "Edit":
        return 0

    inp = ev.get("tool_input") or {}
    file_path = inp.get("file_path", "")

    # Only for Python files in src/
    if not (file_path.endswith(".py") and "/src/" in file_path):
        return 0

    msg = "REQUIRED FOLLOW-UP: Run `python -m pytest` to validate the change. Do not proceed until tests pass."
    print(msg, file=sys.stderr)
    return 2

if __name__ == "__main__":
    sys.exit(main())
